actions.script:
// Find all UserAccounts associated with this party
def userAccounts = ec.entity.find("moqui.security.UserAccount").condition("partyId", finalPartyId).list()
def userIds = userAccounts.collect { it.userId }

if (userIds) {
    // Use standard Moqui Notification Facade
    ec.makeNotificationMessage()
        .message([title: message, lcId: lcId])
        .type("info")
        .topic("TradeFinanceNotification")
        .userIds(userIds as Set)
        .send(true) // persist=true so we can verify "received" in tests
} else {
    ec.logger.info("No UserAccounts found for party [${finalPartyId}], skipping real-time notification.")
}
